var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"EXECUTIVE_NPC_ALPHA_MAJOR","text":{"KOREA":"스캐빈저 놈들이 다이브하는 걸 막지 못했다고?","JPN":"スカベンジャーのダイブを止められなかった？","ENG":"You couldn't stop the Scavengers from Diving?","TWN":"你說無法阻止那些清道夫躍入？"},"stage":{"bg":"BLACK","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"EXECUTIVE_NPC_ALPHA_MAJOR","text":{"KOREA":"그래서, 지금 놈들을 놓쳤다는 말인가?","JPN":"それで、今奴らを逃しただと？","ENG":"Are you saying you lost them?","TWN":"意思是被那些傢伙給逃掉了嗎？"},"stage":{"bg":"BLACK","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"EXECUTIVE_NPC_ALPHA_MAJOR","text":{"KOREA":"연구선을 통째로 인양해 가는데 놓치다니! 하나같이 무능해 빠져서는!","JPN":"研究船を丸ごと盗んでいったのに逃しただと！？　どいつもこいつも無能ばかりだな！","ENG":"They were hauling a research ship behind them, and you lost them! So incompetent, every single one of you!","TWN":"整艘研究船被人劫走，竟然連一個人都抓不到！一群沒用的東西！"},"stage":{"bg":"BLACK","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_HIT_SMASH_BIG"},{"id":"L5_1","type":"dialog","speaker":"EXECUTIVE_NPC_ALPHA_MAJOR","text":{"KOREA":"이러니 용병 나부랭이들을 믿고 일을 맡길 수가 없지……!","JPN":"これだから傭兵なんかに安心して仕事を任せられない……！","ENG":"This is why I can't trust mercenaries.","TWN":"我就說不能放心把事情交代給傭兵的嘛……！"},"stage":{"bg":"BLACK","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"EXECUTIVE_NPC_ALPHA_MAJOR","text":{"KOREA":"……그래도 당신네 회사는 그나마 말귀를 알아듣는 모양이군.","JPN":"……だが、この会社はまだマシなようだな。","ENG":"... At least your company is not as bad as the others.","TWN":"……不過你們公司還算聽得懂人話。"},"stage":{"bg":"BLACK","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"EXECUTIVE_NPC_ALPHA_MAJOR","text":{"KOREA":"다른 놈들이 잔챙이들한테 정신이 팔린 동안 당신네 직원들은 스캐빈저를 쫓았다지?","JPN":"他の連中が雑魚に気を取られている間、そちらの社員はスカベンジャーを追ったと聞いた。","ENG":"While the others were distracted by small fry, your employees followed the Scavengers.","TWN":"在其他人掉入調虎離山的陷阱時，你們的員工反而是去追清道夫對吧？"},"stage":{"bg":"BLACK","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"EXECUTIVE_NPC_ALPHA_MAJOR","text":{"KOREA":"하지만 과정 따위는 중요하지 않아. 사업엔 결과가 전부지.","JPN":"しかし過程なぞ重要ではない。事業は結果が全てだ。","ENG":"But in the business world, what you do doesn't matter; what you get does.","TWN":"不過這也不是重點，公司在乎的只有結果。"},"stage":{"bg":"BLACK","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"EXECUTIVE_NPC_ALPHA_MAJOR","text":{"KOREA":"내가 맡긴 의뢰는 해적 놈들이 훔쳐 간 연구선을 되찾아오는 거요.","JPN":"私が任せた依頼は、海賊が盗んだ研究船を取り戻すことだ。","ENG":"I hired you to retrieve my research ship from the pirates.","TWN":"我的委託是要找回被海盜劫走的研究船。"},"stage":{"bg":"BLACK","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"EXECUTIVE_NPC_ALPHA_MAJOR","text":{"KOREA":"다시 말해, 연구선을 회수해 와야 보수를 받을 수 있다는 뜻이지.","JPN":"つまり、研究船を回収しないと報酬はもらえないという意味になる。","ENG":"In other words, you're not going to get paid until you do.","TWN":"意思就是，沒有研究船就沒有酬勞！"},"stage":{"bg":"BLACK","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"EXECUTIVE_NPC_ALPHA_MAJOR","text":{"KOREA":"방금 내가 한 말, 잘 기억해 두시오.","JPN":"今の言葉を、くれぐれも忘れないように。","ENG":"You'd better remember that.","TWN":"這一點請你們牢牢記住！"},"stage":{"bg":"BLACK","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"야, 이 영감탱이야! 잘했다고 한마디 하면 어디 덧나?!","JPN":"はあ？　おい、ジジイ！　よくやったとかご苦労様の一言も言えないのか？","ENG":"Hey, you old coot! Is it so difficult to say, \\"Good job?\\"","TWN":"這個臭老頭！誇獎我們一下會少塊肉嗎？！"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_HIT_SMASH_BIG"},{"id":"L15_1","type":"dialog","speaker":"KIMSOBIN_ALT_NULL_NULL","text":{"KOREA":"유, 유진아. 이건 단방향 수신 메시지야. 그렇게 소리쳐도 저쪽에는 안 들려.","JPN":"シ、シロコ。これは単方向受信メッセージだよ。そんなに怒っても向こうには聞こえないよ。","ENG":"E-Eujin. This is an inbound simplex message. He can't hear you even if you yell.","TWN":"劉…劉珍，這是單工通訊，你喊破喉嚨對方也聽不到的。"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"KIMSOBIN_ALT_NULL_NULL","text":{"KOREA":"그렇지만 조금 심하네……. 해적들하고 싸우느라 죽거나 다친 사람도 많을 텐데…….","JPN":"それにしてもちょっとひどいね……海賊と戦って怪我したり命を落とした人もいるはずなのに……","ENG":"But he's being really harsh. Lots of people got hurt and even died fighting the pirates.","TWN":"雖然他講話真的很難聽……應該有很多人因為和海盜交手，而受傷或死掉吧……"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"그만큼 연구선에 실려 있는 데이터가 중요하단 뜻이겠지.","JPN":"それぐらい、研究船にあるデータが重要ってことだろうね。","ENG":"He cares so much about the data in the research ship.","TWN":"這就表示研究船裡的資料非常重要！"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"아니면, 애초에 일이 끝나면 살려 둘 생각이 없었다거나…….","JPN":"あるいは、そもそも仕事が終わった後は生かしておくつもりがなかったとか……","ENG":"Or he has no intention of letting us live after this.","TWN":"或者，從一開始他就打算，等事情結束後就要滅口……"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"뭐? 방금 뭐라고 한 거야?","JPN":"ん？　今なんて言ったか？","ENG":"What? What did you just say?","TWN":"什麼？你剛說什麼？"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"아무것도 아냐. 그보다 특이사항 보고해야지.","JPN":"なんでもない。それより特異事項を報告しないと。","ENG":"Nothing. Anyway, we'd better report to the Boss and Vice President.","TWN":"沒有啦！還是先報告特殊事項吧！"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"방금 저 메시지, 사장님이랑 부사장님한테도 갔을 테니까.","JPN":"さっきのメッセージ、社長と副社長のところにも届いたはずだから。","ENG":"I'm sure they've also received that message.","TWN":"剛剛的訊息應該也有傳到老闆跟副總那裡。"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"KIMSOBIN_ALT_NULL_NULL","text":{"KOREA":"앗……. 부사장님 많이 화나셨겠다…….","JPN":"あっ……副社長、怒っただろうね……","ENG":"Ah... The Vice President must be really angry...","TWN":"噢……副總應該很火吧……"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"보고드립니다, 사장님.","JPN":"報告します、社長。","ENG":"Boss, this is Xiao Lin.","TWN":"老闆，有事跟您報告。"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_PHONE"},{"id":"L26_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"이미 알고 계시겠지만 스캐빈저를 제압하는 데 실패했어요.","JPN":"すでにご存知かと思いますが、スカベンジャーの制圧に失敗しました。","ENG":"As you may know already, we've failed to subdue the Scavengers.","TWN":"您應該已經收到消息，追捕清道夫一事我們失手了。"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"다른 해적들의 방해가 있었습니다. 스케빈저 놈들이 끌어들인 것 같아요.","JPN":"他の海賊の妨害がありました。スカベンジャーがわざと巻き込んだようです。","ENG":"Other pirates got in the way. The Scavengers must have dragged them in.","TWN":"原因是受到其他海盜的阻饒，那些海盜似乎是被清道夫引過來的。"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"그래도 너무 걱정 마세요.","JPN":"でも、あまり心配はしないでください。","ENG":"Don't worry, though.","TWN":"但老闆不用太擔心！"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"놈들이 목표인 연구선을 인양 중인 이상, 다시 따라잡을 수 있습니다.","JPN":"連中がターゲットである研究船の引き揚げ中である以上、追いつくことはできます。","ENG":"So long as they're hauling our target ship with them, we can catch up to them anytime.","TWN":"只要我們的目標研究船還在那些傢伙的手上，就一定可以抓到他們！"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"사장님, 혹시 스캐빈저에 대해 들어 본 적 있으신가요?","JPN":"社長、もしかしてスカベンジャーについて聞いたことがありますか？","ENG":"Boss, have you heard about the Scavengers before?","TWN":"老闆，請問您有聽過清道夫嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"블랙 네트워크에서는 연합함대가 스캐빈저를 토벌할 때 병력 중 절반을 잃었다고 합니다.","JPN":"ブラックネットワークでは連合艦隊がスカベンジャーを討伐する際、兵力の半数を失ったそうです。","ENG":"According to the information on the Dark Network, they lost half of their forces to the Administration Coalition Fleet.","TWN":"根據黑色網路的消息，聯合艦隊在討伐清道夫時，幾乎是全軍覆沒。"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"그리고 그 중 대부분이, 마지막 교전에서 나타난 거대한 <color=#ffd34c>무언가</color>에 당했다죠.","JPN":"そしてその大半が、最後の交戦で現れた巨大な<color=#ffd34c>何か</color>にやられたそうです。","ENG":"And most of those they lost got killed by <color=#ffd34c>something</color> gigantic that showed up at the end of the battle.","TWN":"而且聽說，大部分都是死於最後交戰時出現的巨大<color=#ffd34c>東西</color>之手。"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"스캐빈저가 숭배하는 4종 침식체라느니, 구 관리국의 유물이라느니……. 저마다 말은 다르지만요.","JPN":"スカベンジャーが崇拝する第4種侵食体だの、旧管理局の遺物だの……証言はバラバラでしたが。","ENG":"Some say it's a Category 4 C.O. worshipped by the Scavengers. Others say it's an Artifact of the Old Administration. Everyone has a different opinion about it.","TWN":"有人說那東西是清道夫崇拜的4類侵蝕體，也有人說是舊管理局的遺物……說法都不一。"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"부회장이란 자의 이상한 태도가, 혹시 그 정체불명의 무언가와 연관되어 있다면……","JPN":"副会長という者の異常な態度が、もしその正体不明の何かと関連があるなら……","ENG":"What if the Alphatrix vice chairman's strange behavior has to do with this mysterious thing?","TWN":"我猜那個副會長可疑的態度，會不會和那個東西有關呢……"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"아니, 조금 긴장했나 보네요. 방금 한 말은 신경 쓰지 마세요.","JPN":"いえ、少し緊張しすぎたようです。今の言葉は忘れてください。","ENG":"Ah, I must be on edge. Please disregard what I just said.","TWN":"抱歉，可能是我多心了，剛剛那番話請您不用放在心上。"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"다른 태스크포스들이 정비를 마치고 움직이기 시작했습니다.","JPN":"他のタスクフォースカンパニーが整備を終えて動き始めました。","ENG":"The other TASKFORCE companies have regrouped and are moving again.","TWN":"其他特遣勢力已經整頓完畢開始行動了。"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"저희도 이만 출발하도록 하겠습니다. 교신 종료.","JPN":"私たちもそろそろ出発します。交信終了。","ENG":"We should go, too. Over and out.","TWN":"我們也要出發了，結束通訊。"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};